const keywords = ['gta 6', 'gta6', 'gta vi', 'gtavi', 'grand theft auto vi', 'grand theft auto 6', 'rockstar games gta', 'vice city'];
const results = [];

for (const item of $input.all()) {
  const title = (item.json.title || '').toLowerCase();
  const desc = (item.json.contentSnippet || item.json.description || '').toLowerCase();
  const link = (item.json.link || '').toLowerCase();

  const match = keywords.some(kw => title.includes(kw) || desc.includes(kw) || link.includes(kw));
  if (match) {
    // Force the _empty property to false so the downstream 'If' node doesn't drop the item
    results.push({
      json: {
        ...item.json,
        _empty: false
      }
    });
  }
}

if (results.length === 0) {
  return [{ json: { _empty: true, message: 'No GTA 6 news found' } }];
}

return results;

const results = [];
for (const item of $input.all()) {
  const title = item.json.title || '';
  const slug = title
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .substring(0, 80);
  results.push({
    json: {
      ...item.json,
      slug: slug
    }
  });
}
return results;

const item = $input.first();

// Gemini 2.5 Flash may also return thinking parts.
// Get the LAST part which contains the actual JSON response.
const parts = item.json.candidates[0].content.parts;
const text = parts[parts.length - 1].text;

// Clean potential markdown wrapper
let cleaned = text.trim();
if (cleaned.startsWith('```json')) cleaned = cleaned.slice(7);
if (cleaned.startsWith('```')) cleaned = cleaned.slice(3);
if (cleaned.endsWith('```')) cleaned = cleaned.slice(0, -3);
cleaned = cleaned.trim();

// Extra safety: find the JSON object boundaries
const jsonStart = cleaned.indexOf('{');
const jsonEnd = cleaned.lastIndexOf('}');
if (jsonStart !== -1 && jsonEnd !== -1) {
  cleaned = cleaned.substring(jsonStart, jsonEnd + 1);
}

const parsed = JSON.parse(cleaned);

// Map tag to color
